package org.evasive.me.minefinity.npcs.npc;

import org.evasive.me.minefinity.npcs.npc.passive.*;

import java.util.function.Supplier;

public enum NpcType {

    /*ARCHMAGE(
            "Archmage",
            "",
            "",
            0,
            ArchmageNpc::new
    ),*/
    BLACKSMITH(
            "Blacksmith",
            "",
            "",
            0,
            BlacksmithNpc::new
    ),

    BLOCKMASTER(
            "Block Master",
            "",
            "",
            0,
            BlockMasterNpc::new
    ),

    ENGINEER(
            "Engineer",
            "",
            "",
            0,
            EngineerNpc::new
    ),

    GOBLINTINKERER(
            "Goblin Tinkerer",
            "",
            "",
            0,
            GoblinTinkererNpc::new
    ),

    MAYOR(
            "Mayor",
            "",
            "",
            0,
            MayorNpc::new
    ),

    MERCHANT(
            "Merchant",
            "",
            "",
            0,
            MerchantNpc::new
    ),

    MINER(
          "Miner",
          "",
          "",
          0,
          MinerNpc::new
    ),

    SMELTER(
            "Smelter",
            "",
            "",
            0,
            SmelterNpc::new
    )
    ;

    private final String name;
    private final String skin;
    private final String signature;
    private final int requiredQuest;
    private final Supplier<NpcBehavior> behaviorFactory;

    NpcType(String name, String skin, String signature, int requiredQuest, Supplier<NpcBehavior> behaviorFactory) {
        this.name = name;
        this.skin = skin;
        this.signature = signature;
        this.requiredQuest = requiredQuest;
        this.behaviorFactory = behaviorFactory;
    }

    public String getName() { return name; }
    public String getSkin() { return skin; }
    public String getSignature() { return signature; }
    public int getRequiredQuest() { return requiredQuest; }

    public NpcBehavior createBehavior() {
        return behaviorFactory.get();
    }
}
